    "failure_modes": [
      {
        "scenario": "Payment gateway slow (5-8s responses)",
        "handling": "unhandled",
        "recommendation": "CartService times out at 5s but payment may still complete at the gateway. Add idempotency keys to payment requests and a reconciliation process to detect and resolve payments that succeeded after CartService gave up. PaymentService needs a circuit breaker on the gateway with a threshold lower than 8s (e.g., 4s) to fail fast within CartService's budget."
      },
      {
        "scenario": "InventoryService timeout causing OrderService retry to exceed CartService deadline",
        "handling": "unhandled",
        "recommendation": "OrderService retry window (6s max) exceeds CartService timeout (5s). Either remove the retry (accept single-attempt) or reduce InventoryService timeout to 2s so retry fits within budget (2s + 2s = 4s < 5s). Alternatively, add a deadline propagation header so OrderService knows the caller's remaining budget."
      },
      {
        "scenario": "OrderService succeeds but PaymentService fails",
        "handling": "unhandled",
        "recommendation": "Implement a compensation/saga pattern: if PaymentService fails after OrderService succeeds, CartService must call OrderService to cancel the order and release reserved stock. Without this, every payment failure leaks inventory."
