    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [
        "Reconciliation job/worker for orphaned payments",
        "Dead letter queue for failed compensation actions"
      ],
      "new_queues_topics": [
        "Orphaned payment reconciliation queue",
        "Order cancellation compensation queue"
      ],
      "config_changes": [
        "Timeout realignment: PaymentService gateway timeout must be < 5s, InventoryService timeout must allow retry within 5s budget",
        "Add circuit breaker config for CartService->OrderService",
        "Add circuit breaker config for PaymentService->PaymentGateway"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migration details provided. However, inventory reservation leaks imply state is persisted somewhere — need to verify that reservation records have TTL or a cleanup mechanism."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
